#[test]
fn sidecar_round_key_matches_python() {
    let fixture = load_fixture();
    for (i, case) in fixture["sidecar_round_key"]
        .as_array()
        .unwrap()
        .iter()
        .enumerate()
    {
        let chit = f(&case["inputs"]["chit"]);
        let gamma = f(&case["inputs"]["gamma_AB"]);
        let tau = f(&case["inputs"]["tau_obs"]);
        let decimals = case["inputs"]["decimals"].as_i64().unwrap() as i32;
        let (r_chit, r_gamma, r_tau) = round_key(chit, gamma, tau, decimals);
        // Python `round` and Rust `round_ties_even` can disagree by 1 ULP
        // at the rounded precision in pathological halfway cases; LIBM=4
        // covers everything the typical Banach-sidecar producer emits.
        assert_close(
            r_chit,
            f(&case["outputs"]["chit"]),
            LIBM,
            &format!("round_key[{i}].chit"),
        );
        assert_close(
            r_gamma,
            f(&case["outputs"]["gamma_AB"]),
            LIBM,
            &format!("round_key[{i}].gamma_AB"),
        );
        assert_close(
            r_tau,
            f(&case["outputs"]["tau_obs"]),
            LIBM,
            &format!("round_key[{i}].tau_obs"),
        );
    }
}

// ===========================================================================
// Session 4 — flow.rs dispatch (banach_exp / generic / Caputo)
// ===========================================================================

fn build_tangent_flow_field(inputs: &Value) -> TangentFlowField {
    let refinement: Option<BTreeMap<String, Value>> = match &inputs["refinement"] {
        Value::Null => None,
        Value::Object(map) => Some(map.iter().map(|(k, v)| (k.clone(), v.clone())).collect()),
        other => panic!("unexpected refinement shape: {other:?}"),
    };
    let origin = TranslationRule {
        operating_point: OperatingPoint {
            label: "origin".to_string(),
            gt: Gt::S,
            axes: BTreeMap::new(),
        },
        xdot_choice: "default".to_string(),
        canonical: CanonicalPoint {
            chit: 0.0,
            gamma_AB: 0.0,
            k_frust: false,
            method: "test".to_string(),
            extras: BTreeMap::new(),
        },
    };
    TangentFlowField {
        direction: Direction::Forward,
        rule_at_origin: origin,
        scaling: ScalingRule {
            tau_obs_ref: f(&inputs["tau_obs_ref"]),
            delta_chit: f(&inputs["delta_chit"]),
            delta_gamma: f(&inputs["delta_gamma"]),
            refinement,
        },
        description: None,
    }
}

#[test]
fn flow_matches_python_across_dispatch() {
    let fixture = load_fixture();
    for (i, case) in fixture["flow"].as_array().unwrap().iter().enumerate() {
        let inputs = &case["inputs"];
        let field = TranslationField::TangentFlow(build_tangent_flow_field(inputs));
        let initial = CanonicalState {
            chit: f(&inputs["chit_0"]),
            gamma_AB: f(&inputs["gamma_AB_0"]),
            k_frust: false,
        };
        let nu = f(&inputs["nu"]);
        let out = flow(&initial, nu, &field).expect("flow dispatch should succeed");
        // Branch budget: banach_exp / generic compose ≤ 2 libm calls per
        // axis (LIBM); Caputo sums prony_terms.len() exp() calls
        // sequentially (LIBM_WIDE for multi-term cases).
        let budget = if inputs["refinement"]["prony_terms"]
            .as_array()
            .map(|a| a.len() > 1)
            .unwrap_or(false)
        {
            LIBM_WIDE
        } else {
            LIBM
        };
        assert_close(
            out.chit,
            f(&case["outputs"]["chit"]),
            budget,
            &format!("flow[{i}].chit"),
        );
        assert_close(
            out.gamma_AB,
            f(&case["outputs"]["gamma_AB"]),
            budget,
            &format!("flow[{i}].gamma_AB"),
        );
    }
}

// ---------------------------------------------------------------------------
// Session 6 — intent algebra Python→Rust JSON parity
// ---------------------------------------------------------------------------
//
// Not bit-identity (intent_map is pure arithmetic dispatch, no libm) —
// this is a *schema parity* contract. Python is the sacrifice producer
// in the wrapped-variant path (session 7); the test asserts that
// Python-emitted sacrifice JSON deserializes cleanly into the Rust
// `SacrificeRecord` flat-dict shape and reproduces every field.
//
// Asymmetric parity by design: Python's sac dict contains a stored
// `preserved_invariant` STRING key. Rust's `SacrificeRecord` exposes
// the same string via a derived `.preserved_invariant()` method (no
// stored field) — the string is statically determined by the
// `IntentDiagnostics` variant per the BLOCK_IN-prep rationale. serde
// silently drops the unknown field on Python→Rust read. Rust→Python
// round-trip would lose the key; if a future consumer ever needs
// symmetric round-trip, add a custom Serialize on SacrificeRecord
// emitting `preserved_invariant` from the derived method (the BLOCK_IN
// note flags this option). The test asserts the asymmetric path
// works AND that the derived `.preserved_invariant()` matches Python's
// emitted string byte-for-byte, so symmetric parity is a one-line
// serializer away should it ever be needed.

fn parse_intent_id(s: &str) -> IntentId {
    match s {
        "I1" => IntentId::I1,
        "I2" => IntentId::I2,
        "I3" => IntentId::I3,
        "I4" => IntentId::I4,
        "I5" => IntentId::I5,
        other => panic!("unknown intent id in fixture: {other}"),
    }
}

#[test]
fn sacrifice_record_python_to_rust_json_parity() {
    let fixture = load_fixture();
    let cases = fixture["sacrifice_record"]
        .as_array()
        .expect("sacrifice_record array");
    assert!(!cases.is_empty(), "sacrifice_record fixture must be non-empty");
    let mut intents_seen = std::collections::HashSet::new();

    for (i, case) in cases.iter().enumerate() {
        let label = format!("sacrifice_record[{i}]");
        let inputs = &case["inputs"];
        let outputs = &case["outputs"];
        let sac_json = &outputs["sacrifice"];
        let mapped_json = &outputs["mapped"];

        // --- Deserialize: Python's sac dict → Rust SacrificeRecord.
        let rust_sac: SacrificeRecord = serde_json::from_value(sac_json.clone())
            .unwrap_or_else(|e| {
                panic!("{label}: SacrificeRecord deserialize failed: {e}\njson: {sac_json}")
            });

        // --- Deserialize: Python's mapped state → Rust CanonicalState
        // (smoke check that CanonicalState shape matches at the same
        // boundary; the mapped state rides alongside the sacrifice).
        let rust_mapped: CanonicalState = serde_json::from_value(mapped_json.clone())
            .unwrap_or_else(|e| {
                panic!("{label}: CanonicalState deserialize failed: {e}\njson: {mapped_json}")
            });
        let expected_chit = f(&mapped_json["chit"]);
        let expected_gamma = f(&mapped_json["gamma_AB"]);
        assert_eq!(rust_mapped.chit, expected_chit, "{label}: mapped.chit");
        assert_eq!(rust_mapped.gamma_AB, expected_gamma, "{label}: mapped.gamma_AB");
        assert_eq!(
            rust_mapped.k_frust,
            mapped_json["k_frust"].as_bool().expect("k_frust bool"),
            "{label}: mapped.k_frust",
        );

        // --- Common-field parity (outer SacrificeRecord struct).
        let expected_invariant = sac_json["invariant_preserved"]
            .as_bool()
            .expect("invariant_preserved bool");
        assert_eq!(
            rust_sac.invariant_preserved, expected_invariant,
            "{label}: invariant_preserved",
        );
        assert_eq!(
            rust_sac.delta_chit, f(&sac_json["delta_chit"]),
            "{label}: delta_chit",
        );
        assert_eq!(
            rust_sac.delta_gamma_AB, f(&sac_json["delta_gamma_AB"]),
            "{label}: delta_gamma_AB",
        );

        // --- Derived methods match Python's stored strings.
        let expected_intent = parse_intent_id(
            sac_json["intent"].as_str().expect("intent string"),
        );
        assert_eq!(rust_sac.intent(), expected_intent, "{label}: intent()");

        let expected_preserved = sac_json["preserved_invariant"]
            .as_str()
            .expect("preserved_invariant string");
        assert_eq!(
            rust_sac.preserved_invariant(), expected_preserved,
            "{label}: preserved_invariant() derived string",
        );

        // --- Cross-check with the original (state, gamut, intent) inputs.
        // The fixture inputs document the test case; the intent_id field
        // must agree with the sac's intent tag (sanity).
        let intent_input = parse_intent_id(
            inputs["intent_id"].as_str().expect("intent_id string"),
        );
        assert_eq!(
            rust_sac.intent(), intent_input,
            "{label}: sac.intent() must match inputs.intent_id",
        );
        intents_seen.insert(intent_input);

        // --- Per-intent diagnostic parity.
        match (&rust_sac.diagnostics, expected_intent) {
            (
                IntentDiagnostics::I1 {
                    regime_preserved,
                    gamma_AB_sign_preserved,
                    k_frust_preserved,
                    original_regime,
                    mapped_regime,
                    original_gamma_AB_sign,
                    mapped_gamma_AB_sign,
                },
                IntentId::I1,
            ) => {
                assert_eq!(
                    *regime_preserved,
                    sac_json["regime_preserved"].as_bool().expect("bool"),
                    "{label}: I1.regime_preserved",
                );
                assert_eq!(
                    *gamma_AB_sign_preserved,
                    sac_json["gamma_AB_sign_preserved"].as_bool().expect("bool"),
                    "{label}: I1.gamma_AB_sign_preserved",
                );
                assert_eq!(
                    *k_frust_preserved,
                    sac_json["k_frust_preserved"].as_bool().expect("bool"),
                    "{label}: I1.k_frust_preserved",
                );
                let py_orig = sac_json["original_regime"].as_str().expect("regime str");
                let py_mapped = sac_json["mapped_regime"].as_str().expect("regime str");
                assert_eq!(
                    serde_json::to_string(original_regime).unwrap(),
                    format!("\"{py_orig}\""),
                    "{label}: I1.original_regime",
                );
                assert_eq!(
                    serde_json::to_string(mapped_regime).unwrap(),
                    format!("\"{py_mapped}\""),
                    "{label}: I1.mapped_regime",
                );
                assert_eq!(
                    *original_gamma_AB_sign as i64,
                    sac_json["original_gamma_AB_sign"].as_i64().expect("i64"),
                    "{label}: I1.original_gamma_AB_sign",
                );
                assert_eq!(
                    *mapped_gamma_AB_sign as i64,
                    sac_json["mapped_gamma_AB_sign"].as_i64().expect("i64"),
                    "{label}: I1.mapped_gamma_AB_sign",
                );
            }
            (
                IntentDiagnostics::I2 {
                    out_of_gamut_rejected,
                    out_of_gamut_axes,
                },
                IntentId::I2,
            ) => {
                assert_eq!(
                    *out_of_gamut_rejected,
                    sac_json["out_of_gamut_rejected"].as_bool().expect("bool"),
                    "{label}: I2.out_of_gamut_rejected",
                );
                let py_axes: Vec<&str> = sac_json["out_of_gamut_axes"]
                    .as_array()
                    .expect("axes array")
                    .iter()
                    .map(|v| v.as_str().expect("axis str"))
                    .collect();
                assert_eq!(
                    out_of_gamut_axes.len(),
                    py_axes.len(),
                    "{label}: I2.out_of_gamut_axes length",
                );
                for (a, b) in out_of_gamut_axes.iter().zip(py_axes.iter()) {
                    assert_eq!(a, b, "{label}: I2.out_of_gamut_axes element");
                }
            }
            (
                IntentDiagnostics::I3 {
                    capacity_class,
                    mapped_capacity_class,
                    k_frust,
                    k_frust_preserved,
                },
                IntentId::I3,
            ) => {
                let py_cap = sac_json["capacity_class"].as_str().expect("cap str");
                let py_mcap = sac_json["mapped_capacity_class"].as_str().expect("cap str");
                let expected_cap = match py_cap {
                    "deep" => CapacityClass::Deep,
                    "shallow" => CapacityClass::Shallow,
                    other => panic!("{label}: unknown capacity_class: {other}"),
                };
                let expected_mcap = match py_mcap {
                    "deep" => CapacityClass::Deep,
                    "shallow" => CapacityClass::Shallow,
                    other => panic!("{label}: unknown mapped_capacity_class: {other}"),
                };
                assert_eq!(*capacity_class, expected_cap, "{label}: I3.capacity_class");
                assert_eq!(
                    *mapped_capacity_class, expected_mcap,
                    "{label}: I3.mapped_capacity_class",
                );
                assert_eq!(
                    *k_frust,
                    sac_json["k_frust"].as_bool().expect("bool"),
                    "{label}: I3.k_frust",
                );
                assert_eq!(
                    *k_frust_preserved,
                    sac_json["k_frust_preserved"].as_bool().expect("bool"),
                    "{label}: I3.k_frust_preserved",
                );
            }
            (
                IntentDiagnostics::I4 {
                    original_gamma_AB_sign,
                    mapped_gamma_AB_sign,
                },
                IntentId::I4,
            ) => {
                assert_eq!(
                    *original_gamma_AB_sign as i64,
                    sac_json["original_gamma_AB_sign"].as_i64().expect("i64"),
                    "{label}: I4.original_gamma_AB_sign",
                );
                assert_eq!(
                    *mapped_gamma_AB_sign as i64,
                    sac_json["mapped_gamma_AB_sign"].as_i64().expect("i64"),
                    "{label}: I4.mapped_gamma_AB_sign",
                );
            }
            (
                IntentDiagnostics::I5 {
                    regime_preserved,
                    original_regime,
                    mapped_regime,
                },
                IntentId::I5,
            ) => {
                assert_eq!(
                    *regime_preserved,
                    sac_json["regime_preserved"].as_bool().expect("bool"),
                    "{label}: I5.regime_preserved",
                );
                let py_orig = sac_json["original_regime"].as_str().expect("regime str");
                let py_mapped = sac_json["mapped_regime"].as_str().expect("regime str");
                assert_eq!(
                    serde_json::to_string(original_regime).unwrap(),
                    format!("\"{py_orig}\""),
                    "{label}: I5.original_regime",
                );
                assert_eq!(
                    serde_json::to_string(mapped_regime).unwrap(),
                    format!("\"{py_mapped}\""),
                    "{label}: I5.mapped_regime",
                );
            }
            (variant, expected) => panic!(
                "{label}: variant/intent mismatch — Rust variant {variant:?}, expected {expected:?}",
            ),
        }
    }

    // Coverage: every intent should be exercised at least once.
    for required in [IntentId::I1, IntentId::I2, IntentId::I3, IntentId::I4, IntentId::I5] {
        assert!(
            intents_seen.contains(&required),
            "sacrifice_record fixture missing case for {required:?}",
        );
    }
}

// ---------------------------------------------------------------------------
// Session 7 — provenance + wrapped-variant wire parity
// ---------------------------------------------------------------------------

fn parse_dispatch_path(s: &str) -> DispatchPath {
    match s {
        "direct_compute" => DispatchPath::DirectCompute,
        "table_hit" => DispatchPath::TableHit,
        "compute_fallback" => DispatchPath::ComputeFallback,
        other => panic!("unknown dispatch_path: {other}"),
    }
}

fn regime_label_str(label: RegimeLabel) -> &'static str {
    match label {
        RegimeLabel::DeepC => "deep_c",
        RegimeLabel::CNearS => "c_near_s",
        RegimeLabel::SCritical => "s_critical",
        RegimeLabel::RNearS => "r_near_s",
        RegimeLabel::DeepR => "deep_r",
    }
}

/// Cross-language bit-identity for `provenance_hash`. The 4-byte
/// blake2b digest must match Python's exactly — any drift in the
/// (solver_version | operation | dispatch_path | table_version)
/// payload encoding or in the integer-to-`[0, 1)` mapping breaks the
/// EXR-channel provenance fingerprint contract.
#[test]
fn provenance_hash_python_to_rust_parity() {
    let fixture = load_fixture();
    let cases = fixture["provenance_hash"]
        .as_array()
        .expect("provenance_hash array");
    assert!(!cases.is_empty(), "provenance_hash fixture must be non-empty");

    for (i, case) in cases.iter().enumerate() {
        let inputs = &case["inputs"];
        let op = inputs["operation"].as_str().expect("operation str");
        let dp_str = inputs["dispatch_path"].as_str().expect("dispatch_path str");
        let dp = parse_dispatch_path(dp_str);
        let tv = inputs["table_version"].as_str().map(|s| s.to_string());
        let expected = case["output"].as_f64().expect("output f64");

        let prov = make_provenance(op, dp, tv, Vec::new());
        let actual = provenance_hash(&prov);

        // Bit-identity: equal f64 bits. The hash is rational
        // (uint / 2^32) so exact equality is the right contract.
        assert_eq!(
            actual.to_bits(),
            expected.to_bits(),
            "provenance_hash[{i}] ({op}, {dp_str}, {tv:?}): \
             expected {expected:.17e}, got {actual:.17e}",
            tv = inputs["table_version"],
        );
    }

    // Coverage: every dispatch path should appear at least once, and at
    // least one table_version=null + at least one table_version=string.
    let mut dps: BTreeMap<String, bool> = BTreeMap::new();
    let mut has_null_tv = false;
    let mut has_str_tv = false;
    for case in cases {
        let dp = case["inputs"]["dispatch_path"].as_str().unwrap();
        dps.insert(dp.to_string(), true);
        if case["inputs"]["table_version"].is_null() {
            has_null_tv = true;
        } else {
            has_str_tv = true;
        }
    }
    for required in ["direct_compute", "table_hit", "compute_fallback"] {
        assert!(
            dps.contains_key(required),
            "provenance_hash fixture missing dispatch_path={required}",
        );
    }
    assert!(has_null_tv, "fixture missing a null table_version case");
    assert!(has_str_tv, "fixture missing a non-null table_version case");
}

/// Cross-language wire parity for `OperationOutput<RegimeReading>`.
///
/// Structured-field equality only: timestamps are non-deterministic
/// (Python uses `time.monotonic_ns()`, Rust uses `Instant`-elapsed),
/// and the notes diagnostic strings have a float-formatting divergence
/// (`f"{0.0}"` is `"0.0"` in Python, `format!("{}", 0.0)` is `"0"` in
/// Rust — see CLAUDE.md asymmetry note). Both exclusions are by design;
/// the load-bearing contract is the structured flags and the provenance
/// hash inputs.
#[test]
fn operation_output_regime_at_python_to_rust_parity() {
    let fixture = load_fixture();
    let cases = fixture["operation_output_regime_at"]
        .as_array()
        .expect("operation_output_regime_at array");
    assert!(
        !cases.is_empty(),
        "operation_output_regime_at fixture must be non-empty",
    );

    for case in cases {
        let label = case["label"].as_str().unwrap_or("<unlabeled>");
        let inputs = &case["inputs"];
        let canonical = CanonicalState {
            chit: inputs["chit"].as_f64().expect("chit"),
            gamma_AB: inputs["gamma_AB"].as_f64().expect("gamma_AB"),
            k_frust: inputs["k_frust"].as_bool().expect("k_frust"),
        };
        let tau_obs = inputs["tau_obs"].as_f64().expect("tau_obs");

        let out = regime_at_wrapped(&canonical, tau_obs);
        let expected = &case["output"];

        // value: regime label string + k_frust bool
        let py_regime = expected["value"]["regime"].as_str().unwrap();
        assert_eq!(
            regime_label_str(out.value.regime),
            py_regime,
            "{label}: value.regime",
        );
        assert_eq!(
            out.value.k_frust,
            expected["value"]["k_frust"].as_bool().unwrap(),
            "{label}: value.k_frust",
        );

        // validation: three structured flags. Notes excluded per the
        // documented float-formatting asymmetry above.
        assert_eq!(
            out.validation.asymptotic_closure_compliant,
            expected["validation"]["asymptotic_closure_compliant"]
                .as_bool()
                .unwrap(),
            "{label}: asymptotic_closure_compliant",
        );
        assert_eq!(
            out.validation.k_frust_invariant,
            expected["validation"]["k_frust_invariant"].as_bool().unwrap(),
            "{label}: k_frust_invariant",
        );
        let py_rt = &expected["validation"]["round_trip_residual"];
        match (out.validation.round_trip_residual, py_rt) {
            (None, v) if v.is_null() => (),
            (Some(actual), v) if v.is_f64() => {
                let expected_f = v.as_f64().unwrap();
                assert_eq!(
                    actual.to_bits(),
                    expected_f.to_bits(),
                    "{label}: round_trip_residual",
                );
            }
            other => panic!(
                "{label}: round_trip_residual mismatch — Rust {:?}, Python {py_rt}",
                other.0,
            ),
        }

        // provenance: solver_version + operation + dispatch_path + table_version.
        // timestamp_ns excluded (non-deterministic; both impls are monotonic
        // but the reference epoch is process-local on each side).
        assert_eq!(
            out.provenance.solver_version,
            expected["provenance"]["solver_version"].as_str().unwrap(),
            "{label}: solver_version",
        );
        assert_eq!(
            out.provenance.solver_version, SOLVER_VERSION,
            "{label}: Rust SOLVER_VERSION must equal Python __version__",
        );
        assert_eq!(
            out.provenance.operation,
            expected["provenance"]["operation"].as_str().unwrap(),
            "{label}: operation",
        );
        assert_eq!(
            out.provenance.dispatch_path,
            parse_dispatch_path(
                expected["provenance"]["dispatch_path"].as_str().unwrap()
            ),
            "{label}: dispatch_path",
        );
        let py_tv = expected["provenance"]["table_version"].as_str();
        assert_eq!(
            out.provenance.table_version.as_deref(),
            py_tv,
            "{label}: table_version",
        );
    }
}
